import{_ as i,o as a,c as e,a6 as t}from"./chunks/framework.DtxWasON.js";const k=JSON.parse('{"title":"Becoming a Validator","description":"","frontmatter":{},"headers":[],"relativePath":"mainchain/networks/become-validator.md","filePath":"mainchain/networks/become-validator.md"}'),n={name:"mainchain/networks/become-validator.md"};function o(l,s,h,p,d,r){return a(),e("div",null,[...s[0]||(s[0]=[t(`<h1 id="becoming-a-validator" tabindex="-1">Becoming a Validator <a class="header-anchor" href="#becoming-a-validator" aria-label="Permalink to &quot;Becoming a Validator&quot;">​</a></h1><div class="danger custom-block"><p class="custom-block-title">DANGER</p><p>If you intend to become a <code>MainNet</code> Validator, it is <strong>HIGHLY</strong> recommended that you practice on <code>TestNet</code> first in order to fully familiarise yourself with the process.</p></div><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Whenever you use <code>und</code> to send Txs or query the chain ensure you pass the correct data to the <code>--chain-id</code> and if necessary <code>--node=</code> flags so that you connect to the correct network!</p></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Validator nodes require high availability and uptimes. The following guide therefore assumes the node is running on a server/cloud VM, as opposed to a laptop or home PC.</p></div><h4 id="contents" tabindex="-1">Contents <a class="header-anchor" href="#contents" aria-label="Permalink to &quot;Contents&quot;">​</a></h4><nav class="table-of-contents"><ul><li><a href="#prerequisites">Prerequisites</a></li><li><a href="#creating-a-validator">Creating a validator</a><ul><li><a href="#verify">Verify</a></li></ul></li></ul></nav><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>Before continuing, ensure you have gone through the following docs:</p><ol><li><a href="./../software/cosmovisor/install_und_with_cosmovisor.html">Install <code>und</code> and fully sync a node</a></li><li><a href="./../software/accounts-wallets.html">Accounts and Wallets</a></li><li>Chain ID - if you haven&#39;t already, you can get the current chain ID by running:</li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>jq --raw-output &#39;.chain_id&#39; $HOME/.und_mainchain/config/genesis.json</span></span></code></pre></div><p><strong>You will need to run this on the same host that is running your validator node</strong></p><p>The above command assumes you have downloaded the appropriate genesis for the network you wish to become a Validator on to the default <code>$HOME/.und_mainchain</code> directory.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>you will need an account with sufficient FUND to self-delegate to your validator node. For <strong>TestNet</strong> nodes, you can use the <a href="https://faucet-testnet.unification.io" target="_blank" rel="noreferrer">TestNet Faucet</a>.</p></div><h2 id="creating-a-validator" tabindex="-1">Creating a validator <a class="header-anchor" href="#creating-a-validator" aria-label="Permalink to &quot;Creating a validator&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">IMPORTANT!</p><p>keep your <code>$HOME/.und_mainchain/config/node_key.json</code> and <code>$HOME/.und_mainchain/config/priv_validator_key.json</code> files <strong>safe and secure</strong>! These are required for your node to propose and sign blocks. If you ever migrate your node to a different host machine or need to restore your node, you will need these!</p></div><div class="tip custom-block"><p class="custom-block-title">NOTE</p><p>The following commands assume you have initialised your node using the default <code>$HOME/.und_mainchain</code> directory. If you are using a different location, use the <code>--home</code> flag.</p></div><p><strong>If required, SSH to the host running your validator node - the public key output by the following command must be the public key of your validator node!</strong></p><p>The first thing you will need is your node&#39;s Tendermint validator public key. This will be used to register your node as a Validator on the network. To get the key, run:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tendermint</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show-validator</span></span></code></pre></div><p>This will output your node&#39;s public key. Make a note of it, as it will be required soon. You will need the entire JSON string</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Before continuing, ensure your node has fully synced with the network and downloaded all the blocks (this may take a while, so go and make a brew). You can check the status of your node&#39;s sync by running the following from the node host:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:26657/status</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;.result.sync_info.catching_up&#39;</span></span></code></pre></div><p>if the value is <code>false</code>, the node is fully synced</p></div><p>To create your Validator, you will need to generate, sign and broadcast a special transaction to the network which will register your Tendermint validator public key and stake the amount of FUND (in <code>nund</code>) specified (via self-delegation). Run the following command, modifying as required (<strong>this command can be run from your local host, or the node host, depending on where you generated the account wallet in Prerequisite #3</strong>)</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> staking</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-validator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --amount=STAKE_IN_NUND</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --pubkey=NODE_TENDERMINT_PUBLIC_KEY</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --moniker=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;YOUR_VALIDATOR_MONIKER&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --website=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;YOUR_WEBSITE_URL&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --identity=16_DIGIT_KEYBASE_IO_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --details=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;NODE_DESCRIPTION&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --security-contact=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;SECURITY_CONTACT_EMAIL&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --chain-id=CHAIN_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --commission-rate=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.10&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --commission-max-rate=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.20&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --commission-max-change-rate=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.01&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --min-self-delegation=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --gas=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;auto&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --gas-prices=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.25nund&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --gas-adjustment=1.5</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --from=SELF_DELEGATOR_ACCOUNT</span></span></code></pre></div><p><strong>Mandatory fields</strong></p><p><code>STAKE_IN_NUND</code>: the amount in nund you want to delegate to yourself. For example, if you want to stake 1000 FUND, enter 1000000000000nund.</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>You can use the built in <code>und</code> conversion tool to calculate this:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>und convert 1000 fund nund.</span></span></code></pre></div></div><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>do not attempt to stake more than you have in your account. <strong>Ensure you have enough FUND to pay for the transaction fees, and enough left over for future transactions such as withdrawing rewards!</strong></p></div><p><code>NODE_TENDERMINT_PUBLIC_KEY</code>: Your node&#39;s Protobuf JSON encoded tendermint public key, obtained earlier via the <code>und tendermint show-validator</code> command.</p><p><code>CHAIN_ID</code>: the chain you are creating a validator for. This was obtained previously via the <code>jq</code> command, and will be for example <code>FUND-TestNet-2</code> or <code>FUND-MainNet-2</code> etc.</p><p><code>SELF_DELEGATOR_ACCOUNT</code>: the name of the account being used to stake self-delegated FUND and sign the transaction — for example, the identifier you entered when running the <code>und keys add</code> command to create/import an account.</p><p><code>YOUR_VALIDATOR_MONIKER</code>: a moniker which will publicly identify your Validator node on the network.</p><p><strong>Optional fields</strong></p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Ensure you create your validator with as much of the following additional information as you can. It will be publicly visible, and help potential stakers connect with you</p></div><p><code>YOUR_WEBSITE_URL</code>: the URL for the site promoting your validation node</p><p><code>16_DIGIT_KEYBASE_IO_ID</code>: Your 16 digit public <a href="https://keybase.io" target="_blank" rel="noreferrer">keybase.io</a> PGP public key ID if you have one and want to associate your ID to your validator node.</p><p><code>NODE_DESCRIPTION</code>: a brief description of your validator node</p><p><code>SECURITY_CONTACT_EMAIL</code>: Email address for the security contact for your validator node</p><p><strong>Commission Rates</strong></p><p>Your commission rates can be set using the <code>--commission-rate</code> , <code>--commission-max-change-rate</code> and <code>--commission-max-rate</code> flags.</p><p><code>--commission-rate</code>: The % commission you will earn from delegators’ rewards. Keeping this relatively low can attract more delegators to your node.</p><p><code>--commission-max-rate</code>: The maximum you will ever increase your commission rate to — you cannot raise commission above this value. Again, keeping this low can attract more delegators.</p><p><code>--commission-max-change-rate</code>: The maximum you can increase the commission-rate by per day. For example, if your maximum change rate is 0.01, you can only make changes in 0.01 increments, so from 0.10 (10%) to 0.11 (11%).</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>The values for <code>--commission-max-change-rate</code> and <code>--commission-max-rate</code> flags <strong>cannot be changed</strong> after the <code>create-validator</code> command has been run.</p></div><p>Finally, the <code>--min-self-delegation</code> flag is the minimum amount of <code>nund</code> you are required to keep self-delegated to your validator, meaning you must always have <em>at least</em> this amount self-delegated to your node.</p><p><strong>Example: creating a TestNet validator</strong></p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> staking</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create-validator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--amount=1000000000000nund </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--pubkey=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;{&quot;@type&quot;:&quot;/cosmos.crypto.ed25519.PubKey&quot;,&quot;key&quot;:&quot;abc123...=&quot;}&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--moniker=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;MyAwesomeNode&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--website=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://my-node-site.com&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--details=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;My node is awesome&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--security-contact=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;security@my-node-site.com&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--chain-id=FUND-TestNet-2 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--commission-rate=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.07&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--commission-max-rate=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.20&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--commission-max-change-rate=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.01&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--min-self-delegation=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;1000000000&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--gas=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;auto&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--gas-prices=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;0.25nund&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--gas-adjustment=1.5 </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">--from=my_new_wallet</span></span></code></pre></div><p>The command will return a Tx hash, which you can use to query whether or not the transaction was successful:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TX_HASH</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --chain-id</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> FUND-TestNet-2</span></span></code></pre></div><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>you can set the <code>--broadcast-mode</code> flag in the command to <code>block</code>. This will tell <code>und</code> to wait for the transaction to be processed in a block before returning the result. This will take up to 5-6 seconds to complete, but the Tx result will be included in the output.</p></div><h3 id="verify" tabindex="-1">Verify <a class="header-anchor" href="#verify" aria-label="Permalink to &quot;Verify&quot;">​</a></h3><p>You can verify your node is registered as a validator by running:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> query</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> staking</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> validator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  $(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">und</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> keys</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> show</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SELF_DELEGATOR_ACCOUNT</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --bech=val</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -a</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">\\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --chain-id=CHAIN_ID</span></span></code></pre></div><p>replacing <code>SELF_DELEGATOR_ACCOUNT</code> and <code>CHAIN_ID</code> accordingly.</p>`,53)])])}const u=i(n,[["render",o]]);export{k as __pageData,u as default};
